; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Harpy Mountain - watch out for harpy attacks ahead!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove

@wait time=500
@fg l=bandit_yellow left=300 top=80 b
@fg c=bandit_yellow left=450 top=80 b
@fgf r=bandit_yellow left=600 top=80
[texton]
[name n=Bandit]「What the hell are you guys doing?」[k]
[name n=Bandit]「You're disturbing my work! Get out of here now!」[k]
[textoff]
@question title="Will you leave?" cancel=true

[if exp='tf.result']
	@clf
	@walk move=w
	[eventoff]
[endif]

[texton]
[name n=Bandit]「What?!」[k]
[textoff]
@clf
@monster pos=2 name=バンディット
@monster pos=3 name=バンディット
@monster pos=4 name=バンディット
@callbattle gameover=true
@delevent
@eval exp='f.killedBanditsRapeGnome = true'

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] party.lastIsMove

; イベント時の移動制限。ダンジョンに入れないようにする
[texton]
[テオ f=06]「We should go somewhere else.」[k]
[textoff]
@walk move=s cond='game.party.curX == 21'
@walk move=w cond='game.party.curX == 25'

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

@notice text="You can't go any further in the trial version."
@walk move=w

[eventoff]
;-------------------------------------------------------------------------------
